mapper.select:
SELECT pr.*, u.nickname, u.phone
FROM points_request pr
LEFT JOIN `user` u ON u.id = pr.user_id AND u.deleted = 0
WHERE pr.deleted = 0
AND u.store_id = #{storeId}
AND pr.user_id = #{userId}
AND pr.type = #{type}
AND pr.status = #{status}
ORDER BY pr.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM points_request pr
LEFT JOIN `user` u ON u.id = pr.user_id AND u.deleted = 0
WHERE pr.deleted = 0
AND u.store_id = #{storeId}
AND pr.user_id = #{userId}
AND pr.type = #{type}
AND pr.status = #{status}
